{"query":"
query validation($address: AddressInput!, $locale: String!, $matchingStrategy: MatchingStrategy) {
  validation(address: $address, locale: $locale, matchingStrategy: $matchingStrategy) {
    validationScope
    locale
    fields {
      name
      value
    }
    concerns {
      fieldNames
      code
      type
      typeLevel
      suggestionIds
      message
    }
    id
    suggestions {
      id
      address1
      streetName
      streetNumber
      address2
      line2
      neighborhood
      city
      zip
      provinceCode
      province
      countryCode
    }
  }
}
